#[cfg(test)]
mod tests {
    use super::*;
    use tokio::io::{AsyncReadExt, AsyncWriteExt};
    use tracing::{info, debug};

    #[tokio::test]
    async fn test_tls_stream_echo() {
        info!("Testing TLS stream echo");

        // Setup test certs (from test files)
        let chain = test_chain();
        let key = test_key();

        let acceptor = TlsAcceptorBuilder::new(chain.clone(), key)
            .build()
            .unwrap();

        let connector = TlsConnectorBuilder::new()
            .add_root_certificates(chain.certs().iter().cloned())
            .build()
            .unwrap();

        let (client_io, server_io) = tokio::io::duplex(8192);

        // Server task
        let server = tokio::spawn(async move {
            let mut stream = acceptor.accept(server_io).await.unwrap();

            let mut buf = [0u8; 1024];
            let n = stream.read(&mut buf).await.unwrap();
            debug!(bytes = n, "Server received");

            stream.write_all(&buf[..n]).await.unwrap();
            stream.flush().await.unwrap();
            stream.shutdown().await.unwrap();
        });

        // Client task
        let client = tokio::spawn(async move {
            let mut stream = connector.connect("localhost", client_io).await.unwrap();

            stream.write_all(b"Hello, TLS!").await.unwrap();
            stream.flush().await.unwrap();

            let mut buf = [0u8; 1024];
            let n = stream.read(&mut buf).await.unwrap();
            debug!(bytes = n, "Client received");

            assert_eq!(&buf[..n], b"Hello, TLS!");
            stream.shutdown().await.unwrap();
        });

        let (server_result, client_result) = tokio::join!(server, client);
        server_result.unwrap();
        client_result.unwrap();

        info!("TLS echo test passed");
    }

    #[tokio::test]
    async fn test_tls_stream_large_data() {
        info!("Testing TLS stream with large data");

        let chain = test_chain();
        let key = test_key();

        let acceptor = TlsAcceptorBuilder::new(chain.clone(), key)
            .build()
            .unwrap();

        let connector = TlsConnectorBuilder::new()
            .add_root_certificates(chain.certs().iter().cloned())
            .build()
            .unwrap();

        let (client_io, server_io) = tokio::io::duplex(8192);

        // 1 MB of data
        let data: Vec<u8> = (0..1_000_000).map(|i| (i % 256) as u8).collect();
        let data_clone = data.clone();

        let server = tokio::spawn(async move {
            let mut stream = acceptor.accept(server_io).await.unwrap();

            let mut received = Vec::new();
            stream.read_to_end(&mut received).await.unwrap();

            assert_eq!(received, data_clone);
            debug!(bytes = received.len(), "Server received all data");
        });

        let client = tokio::spawn(async move {
            let mut stream = connector.connect("localhost", client_io).await.unwrap();

            stream.write_all(&data).await.unwrap();
            stream.shutdown().await.unwrap();
            debug!(bytes = data.len(), "Client sent all data");
        });

        let (server_result, client_result) = tokio::join!(server, client);
        server_result.unwrap();
        client_result.unwrap();

        info!("Large data TLS test passed");
    }

    #[tokio::test]
    async fn test_tls_stream_alpn() {
        info!("Testing TLS ALPN negotiation");

        let chain = test_chain();
        let key = test_key();

        let acceptor = TlsAcceptorBuilder::new(chain.clone(), key)
            .alpn_protocols(vec![b"h2".to_vec(), b"http/1.1".to_vec()])
            .build()
            .unwrap();

        let connector = TlsConnectorBuilder::new()
            .add_root_certificates(chain.certs().iter().cloned())
            .alpn_protocols(vec![b"h2".to_vec()])
            .build()
            .unwrap();

        let (client_io, server_io) = tokio::io::duplex(8192);

        let server = tokio::spawn(async move {
            let stream = acceptor.accept(server_io).await.unwrap();
            assert_eq!(stream.alpn_protocol(), Some(b"h2".as_slice()));
            debug!(alpn = ?stream.alpn_protocol(), "Server ALPN");
        });

        let client = tokio::spawn(async move {
            let stream = connector.connect("localhost", client_io).await.unwrap();
            assert_eq!(stream.alpn_protocol(), Some(b"h2".as_slice()));
            debug!(alpn = ?stream.alpn_protocol(), "Client ALPN");
        });

        let (server_result, client_result) = tokio::join!(server, client);
        server_result.unwrap();
        client_result.unwrap();

        info!("ALPN negotiation test passed");
    }
}
